    relLinks.filter\(l => !l.includes\("catalogsearch"\) && !l.includes\("customer"\) && !l.includes\("css"\) && !l.includes\(".js"\)\)
      .slice\(0,15\).forEach\(l => console.log\(l\)\);
  }\)
  .catch\(e => console.error\(e\)\);
